<tr><td style="padding:10px 14px;border-bottom:1px solid rgba(255,255,255,0.08);">Vizör</td><td style="padding:10px 14px;border-bottom:1px solid rgba(255,255,255,0.08);">Yok</td><td style="padding:10px 14px;border-bottom:1px solid rgba(255,255,255,0.08);">Opsiyonel çıkarılabilir OLED vizör</td></tr>
<tr><td style="padding:10px 14px;border-bottom:1px solid rgba(255,255,255,0.08);">Ses</td><td style="padding:10px 14px;border-bottom:1px solid rgba(255,255,255,0.08);">Dahili + opsiyonel XLR adaptör</td><td style="padding:10px 14px;border-bottom:1px solid rgba(255,255,255,0.08);">Opsiyonel XLR tutamak, 32-bit float destekli</td></tr>
