<tr><td style="padding:10px 14px;border-bottom:1px solid rgba(255,255,255,0.08);">Çıkış Yılı</td><td style="padding:10px 14px;border-bottom:1px solid rgba(255,255,255,0.08);">2021 (FX3A güncellemesi 2025)</td><td style="padding:10px 14px;border-bottom:1px solid rgba(255,255,255,0.08);">2026</td></tr>
